# The following file was generated by Codex to quickly visualize the gentrification prediction scores on a map of Chicago census tracts. 
# It reads in the scored CSV and shapefile, merges them, and produces both static and interactive maps colored by the predicted gentrification probability.

from pathlib import Path
from string import Template

import geopandas as gpd
import matplotlib.pyplot as plt
import pandas as pd
from matplotlib.colors import TwoSlopeNorm
from matplotlib.cm import ScalarMappable


ROOT = Path(__file__).resolve().parent
SCORED_CSV = ROOT / "predictions_top20.csv"
TRACT_SHP = ROOT / "data" / "tl_2020_17_tract" / "tl_2020_17_tract.shp"
OUTPUT_DIR = ROOT / "visualized_outputs"
PNG_OUT = OUTPUT_DIR / "gentrification_score_map.png"
SVG_OUT = OUTPUT_DIR / "gentrification_score_map.svg"
HTML_OUT = OUTPUT_DIR / "gentrification_score_map.html"
target_value = "predicted_gentrification_prob"


def load_scored_tracts() -> gpd.GeoDataFrame:
    scores = pd.read_csv(SCORED_CSV, dtype={"GEOID": str})
    scores["GEOID"] = scores["GEOID"].str.zfill(11)

    if target_value not in scores.columns:
        raise ValueError(f"{SCORED_CSV.name} must include a gentrification_score column.")

    tracts = gpd.read_file(TRACT_SHP)
    tracts["GEOID"] = tracts["GEOID"].astype(str).str.zfill(11)

    mapped = tracts.merge(
        scores[["GEOID", target_value]],
        on="GEOID",
        how="inner",
        validate="one_to_one",
    )

    if mapped.empty:
        raise ValueError("No census tracts matched between the shapefile and scored CSV.")

    return mapped


def plot_gentrification_map(gdf: gpd.GeoDataFrame) -> None:
    OUTPUT_DIR.mkdir(exist_ok=True)

    # Web Mercator keeps the tract shapes visually stable for a compact city-scale map.
    plot_gdf = gdf.to_crs(epsg=3857)
    scores = plot_gdf[target_value]
    scored = plot_gdf[scores.notna()]
    missing = plot_gdf[scores.isna()]

    vmax = max(abs(scored[target_value].min()), abs(scored[target_value].max()))
    norm = TwoSlopeNorm(vmin=-vmax, vcenter=0, vmax=vmax)
    cmap = "RdYlGn"

    fig, ax = plt.subplots(figsize=(11, 12), dpi=200)
    ax.set_facecolor("#f7f7f4")

    if not missing.empty:
        missing.plot(ax=ax, color="#d9d9d9", edgecolor="#ffffff", linewidth=0.15)

    scored.plot(
        ax=ax,
        column=target_value,
        cmap=cmap,
        norm=norm,
        edgecolor="#ffffff",
        linewidth=0.18,
    )

    ax.set_title("Chicago Census Tracts by Gentrification Score", fontsize=18, pad=16)
    ax.set_axis_off()

    colorbar = fig.colorbar(
        ScalarMappable(norm=norm, cmap=cmap),
        ax=ax,
        orientation="horizontal",
        fraction=0.035,
        pad=0.02,
    )
    colorbar.set_label("Gentrification score", fontsize=11)

    fig.text(
        0.5,
        0.025,
        "Green = higher score; red = lower score. Gray tracts have missing scores.",
        ha="center",
        fontsize=9,
        color="#555555",
    )

    fig.savefig(PNG_OUT, bbox_inches="tight")
    fig.savefig(SVG_OUT, bbox_inches="tight")
    plt.close(fig)


def write_interactive_map(gdf: gpd.GeoDataFrame) -> None:
    OUTPUT_DIR.mkdir(exist_ok=True)

    web_gdf = gdf.to_crs(epsg=4326)[["GEOID", target_value, "geometry"]]
    geojson = web_gdf.to_json(na="null")

    scored = gdf[target_value].dropna()
    vmax = max(abs(scored.min()), abs(scored.max()))

    html = Template(
        """<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Chicago Gentrification Prediction Map</title>
  <link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css">
  <script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"></script>
  <style>
    html, body, #map { height: 100%; margin: 0; }
    body { font-family: Arial, sans-serif; }
    .legend {
      background: white;
      border: 1px solid #bbb;
      border-radius: 4px;
      box-shadow: 0 1px 5px rgba(0, 0, 0, 0.22);
      color: #222;
      line-height: 1.35;
      padding: 10px 12px;
    }
    .legend-title { font-weight: 700; margin-bottom: 6px; }
    .legend-ramp {
      background: linear-gradient(90deg, #a50026, #ffffbf, #006837);
      height: 12px;
      margin: 6px 0;
      width: 190px;
    }
    .legend-labels {
      display: flex;
      font-size: 12px;
      justify-content: space-between;
      width: 190px;
    }
  </style>
</head>
<body>
  <div id="map"></div>
  <script>
    const tractData = $geojson;
    const scoreLimit = $score_limit;

    const map = L.map("map", { preferCanvas: true });
    L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", {
      maxZoom: 19,
      attribution: "&copy; OpenStreetMap contributors"
    }).addTo(map);

    function lerp(a, b, t) {
      return Math.round(a + (b - a) * t);
    }

    function hexToRgb(hex) {
      const clean = hex.replace("#", "");
      return [
        parseInt(clean.slice(0, 2), 16),
        parseInt(clean.slice(2, 4), 16),
        parseInt(clean.slice(4, 6), 16)
      ];
    }

    function rgbToHex(rgb) {
      return "#" + rgb.map(v => v.toString(16).padStart(2, "0")).join("");
    }

    function interpolateColor(left, right, t) {
      const a = hexToRgb(left);
      const b = hexToRgb(right);
      return rgbToHex([lerp(a[0], b[0], t), lerp(a[1], b[1], t), lerp(a[2], b[2], t)]);
    }

    function colorForScore(score) {
      if (score === null || Number.isNaN(score)) {
        return "#d9d9d9";
      }
      const clamped = Math.max(-scoreLimit, Math.min(scoreLimit, score));
      const normalized = (clamped + scoreLimit) / (2 * scoreLimit);
      if (normalized < 0.5) {
        return interpolateColor("#a50026", "#ffffbf", normalized * 2);
      }
      return interpolateColor("#ffffbf", "#006837", (normalized - 0.5) * 2);
    }

    const tracts = L.geoJSON(tractData, {
      style: feature => ({
        color: "#ffffff",
        fillColor: colorForScore(feature.properties.predicted_gentrification_prob),
        fillOpacity: 0.82,
        opacity: 0.9,
        weight: 0.65
      }),
      onEachFeature: (feature, layer) => {
        const score = feature.properties.predicted_gentrification_prob;
        const scoreText = score === null ? "Missing" : Number(score).toFixed(3);
        layer.bindTooltip(`GEOID: $${feature.properties.GEOID}<br>Score: $${scoreText}`);
        layer.on({
          mouseover: event => event.target.setStyle({ weight: 2, color: "#222222" }),
          mouseout: event => tracts.resetStyle(event.target)
        });
      }
    }).addTo(map);

    map.fitBounds(tracts.getBounds(), { padding: [18, 18] });

    const legend = L.control({ position: "bottomright" });
    legend.onAdd = function () {
      const div = L.DomUtil.create("div", "legend");
      div.innerHTML = `
        <div class="legend-title">Gentrification Probability</div>
        <div class="legend-ramp"></div>
        <div class="legend-labels">
          <span>$${(-scoreLimit).toFixed(1)}</span>
          <span>0</span>
          <span>$${scoreLimit.toFixed(1)}</span>
        </div>
      `;
      return div;
    };
    legend.addTo(map);
  </script>
</body>
</html>
"""
    ).substitute(geojson=geojson, score_limit=repr(float(vmax)))

    HTML_OUT.write_text(html, encoding="utf-8")


def main() -> None:
    mapped = load_scored_tracts()
    plot_gentrification_map(mapped)
    write_interactive_map(mapped)

    total_scores = pd.read_csv(SCORED_CSV).shape[0]
    matched = len(mapped)
    missing_scores = mapped[target_value].isna().sum()

    print(f"Matched {matched:,} of {total_scores:,} scored GEOIDs to tract shapes.")
    print(f"Tracts with missing gentrification_score values: {missing_scores:,}")
    print(f"Wrote {PNG_OUT}")
    print(f"Wrote {SVG_OUT}")
    print(f"Wrote {HTML_OUT}")


if __name__ == "__main__":
    main()
